  { title:"Rich Dad Poor Dad", author:"Robert Kiyosaki", cover:"https://covers.openlibrary.org/b/isbn/9781612680194-L.jpg" },
  { title:"The Psychology of Money", author:"Morgan Housel", cover:"https://covers.openlibrary.org/b/isbn/9780857197689-L.jpg" },
  { title:"The Intelligent Investor", author:"Benjamin Graham", cover:"https://covers.openlibrary.org/b/isbn/9780060555665-L.jpg" },
  { title:"I Will Teach You to Be Rich", author:"Ramit Sethi", cover:"https://covers.openlibrary.org/b/isbn/9780761147480-L.jpg" }
],

SelfHelp: [
  { title:"How to Win Friends & Influence People", author:"Dale Carnegie", cover:"https://covers.openlibrary.org/b/isbn/9780671027032-L.jpg" },
  { title:"The Subtle Art of Not Giving a F*ck", author:"Mark Manson", cover:"https://covers.openlibrary.org/b/isbn/9780062457714-L.jpg" },
  { title:"Deep Work", author:"Cal Newport", cover:"https://covers.openlibrary.org/b/isbn/9781455586691-L.jpg" },
  { title:"7 Habits of Highly Effective People", author:"Stephen Covey", cover:"https://covers.openlibrary.org/b/isbn/9780743269513-L.jpg" }
]
};

function CategoryBooks() {
  const { name } = useParams();
  const navigate = useNavigate();

  const books = data[name] || [];

  return (
    <div className="books-page">
      <h1 className="books-title">{name}</h1>

      <div className="books-grid">
        {books.map((b, i) => (
          <div
            key={i}
            className="book-card"
            onClick={() =>
              navigate(
                `/book/${encodeURIComponent(b.title)}/${encodeURIComponent(
                  b.author
                )}/${encodeURIComponent(b.cover)}`
              )
            }
          >
            <img
              src={b.cover}
              alt={b.title}
              onError={(e) =>
                (e.target.src =
                  "https://via.placeholder.com/200x280?text=No+Cover")
              }
            />
            <h3>{b.title}</h3>
            <p>{b.author}</p>
          </div>
        ))}
      </div>
    </div>
  );
  
}

export default CategoryBooks;
